var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"전조 프로토콜 3분 전","JPN":"前兆プロトコル3分前","ENG":"3 minutes before the Omen Protocol","TWN":"前兆協議3分鐘前","DEU":"3 minutes before the Omen Protocol","FRA":"3 minutes before the Omen Protocol"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>샤레이드</color> 대균열 중심부","JPN":"管理局直轄都市<color=#ffd34c>シャレード</color>大亀裂中心部","ENG":"Administration Direct Control City, <color=#ffd34c>Charade</color> Center of the Grand Dimension Crevice","TWN":"管理局直轄城市<color=#ffd34c>查雷德</color>大峽谷中心","DEU":"Administration Direct Control City, <color=#ffd34c>Charade</color> Center of the Grand Dimension Crevice","FRA":"Administration Direct Control City, <color=#ffd34c>Charade</color> Center of the Grand Dimension Crevice"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"끝이로군.","JPN":"失敗に終わったか。","ENG":"So this is the end.","TWN":"結束了啊。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"계시의 인도를 따라 순례를 준비하며, 그렇게 많은 시간과 노력을 기울였건만…….","JPN":"啓示の導きに従い巡礼を準備し、あれほどの時間と努力を費やしたというのに……","ENG":"I prepared for the pilgrimage, following the guidance of revelation, and poured so much time and effort into it...","TWN":"我循著啟示的指引準備朝聖，耗費了那麼多時間與心力……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"결국은 이런 꼴인가…….","JPN":"結局はこの様か……","ENG":"And this is how it ends...","TWN":"最後卻落得這種下場……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"크윽……!","JPN":"くっ……！","ENG":"Kgh...!","TWN":"呃……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"이제 상처가 아물지 않아.","JPN":"もう傷が塞がらない。","ENG":"My wounds are not healing anymore.","TWN":"傷口已經無法癒合了。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"리플레이서 시술의 효과가 한계에 달했나?","JPN":"リプレイサー施術の効果が限界に達したのか？","ENG":"Have the Replacer enhancements reached their limit?","TWN":"克隆手術的效果終於到極限了嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"후후. 하긴 이런 누더기 같은 몸이 아니었다면, 벌써 오래전에 비명횡사했겠지…….","JPN":"ふふ、それもそうか。こうも至る所に手を加えた体でなければ、とうの昔に死んでいた……","ENG":"Hehe. Well, if it weren't for this patchwork body, I'd have died screaming long ago...","TWN":"呵呵，也是。如果不是這副破破爛爛的身體，早就橫死街頭了吧……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"……대답해다오, 마왕의 권속이여.","JPN":"……答えてくれ、魔王の眷属よ。","ENG":"Heed my call, kin of the Demon Lord.","TWN":"……魔王的手下還真厲害。"},"stage":{"bg":"QLIPHOTH","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"내가 여지껏 찾던 구원은…… 모조리 허황된 것이란 말인가?","JPN":"今まで私が探していた救いは……すべて絵空事だったのか？","ENG":"The salvation I have been looking for... Was it all for naught?","TWN":"難道我過去所追求的救贖……到頭來只是一場空嗎？"},"stage":{"bg":"QLIPHOTH","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"불가역적인 운명이라고 믿었기에, 거사를 결행했다.","JPN":"不可逆的な運命だと信じたゆえに、大事を決行した。","ENG":"I believed it was an irreversible fate, so I carried out my design.","TWN":"正因為我相信那是不可逆的命運，才會付諸行動。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"계시의 인도가 나를 이곳으로 이끌었기에, 어떤 가시밭길이라도 걸을 수 있었어.","JPN":"啓示が私をここに導いたゆえに、どんな茨の道でも歩むことができた。","ENG":"The guidance of revelation led me here, and so I could walk any path of thorns.","TWN":"因為啟示的引導將我帶到這裡，哪怕佈滿荊棘我也能繼續走下去。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"하지만 신의 그릇을 잃어버린 이상, 더는 의식이 불가능해.","JPN":"しかし神の器を失った以上、儀式の続行は不可能だ。","ENG":"But now that I've lost the god's vessel, the ritual is no longer possible.","TWN":"但是，既然神之器皿已遺失，儀式也不可能完成了。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"참으로 허망하군. 이 순례는 여기서 끝인가…….","JPN":"実に虚しい。この巡礼はここで終わるのか……","ENG":"How utterly futile. Is this pilgrimage to end here...?","TWN":"真空虛，朝聖就到此為止了嗎……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"예하, 어쩌면 저는…….","JPN":"猊下、もしかすると私は……","ENG":"Your Eminence, perhaps I...","TWN":"主教，也許我……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_QM","text":{"KOREA":"콘스탄틴… 신부님……?","JPN":"コンスタンティン……神父様……？","ENG":"Father... Constantine...?","TWN":"康斯坦丁……神父……？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_QM","text":{"KOREA":"정말로, 콘스탄틴 신부님 맞아요……?","JPN":"本当に、コンスタンティン神父様ですか……？","ENG":"It really is you, Father Constantine...?","TWN":"真的是康斯坦丁神父嗎……？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"허……?","JPN":"は……？","ENG":"Huh...?","TWN":"啊……？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"역시 콘스탄틴 신부님이 맞으시군요…….","JPN":"やはり、神父様なのですね……","ENG":"So it truly is you, Father Constantine...","TWN":"果然是康斯坦丁神父沒錯呢……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"그렇다면, 정말로 샤레이드에서 발생한 사태는 신부님이 저지른 건가요……?","JPN":"では、本当にシャレードで起きた事件は、神父様が起こしたのですか……？","ENG":"Then, was it really you who caused what happened in Charade...?","TWN":"那麼，查雷德發生的那起事件，真的都是神父您一手造成的嗎……？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"어째서 이렇게 끔찍한 짓을…….","JPN":"どうしてこんな酷いことを……","ENG":"Why would you do something so terrible...?","TWN":"為什麼要做出這麼殘酷的事……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"클로디아… 넬슨이라고……?","JPN":"クラウディア……ネルソンだと……？","ENG":"Claudia... Nelson...?","TWN":"你叫克勞迪婭……尼爾森嗎……？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"네가, 어째서……?","JPN":"君が、なぜ……？","ENG":"Why... are you...?","TWN":"你為什麼會……？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"대답해! 능력을 상실하고 성무에서 배제되었을 네가 어째서 여기에 있지……?","JPN":"答えろ！　能力を失い、聖務から外されたはずの君がなぜここにいる……？","ENG":"Answer me! You should have lost your ability and been excluded from the sacred mission. Why are you here...?","TWN":"回答我！你明明已經失去能力、被排除在聖務之外，為什麼會出現在這裡……？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"틀림없이… 심의회 놈들은 너를 데려오지 않았다고 했는데……?","JPN":"審議会のやつらは君を連れてこなかったと言ったはず……","ENG":"Surely... The Investigation Council said they weren't bringing you...","TWN":"明明……議會那些傢伙沒說會把你帶來啊……？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"의심할 수 없을 때까지, 의심해라. 요한 추기경의 가르침이죠.","JPN":"疑えなくなるまで疑え。ヨハン枢機卿の教えです。","ENG":"Doubt until thou cannot doubt any more. Cardinal Johan's teaching.","TWN":"在深信不疑之前，就持續懷疑。這是約翰樞機主教的教誨。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"저는 다른 사람이 아닌, 신부님의 이야기를 직접 듣고 싶어서 온 거예요.","JPN":"私は他の誰でもない、神父様から直接話を聞きたくてここに来ました。","ENG":"I came because I wanted to hear it from you, Father. Not from anyone else.","TWN":"我不是為了別人而來的。我是想親耳聽神父的說法，才會來到這裡。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"이, 이야기라고……?","JPN":"は、話だと……？","ENG":"H-hear it from me...?","TWN":"說、說法……？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"제가 아는 신부님이라면, 이런 짓을 저지를 리 없으니까.","JPN":"私の知る神父様なら、こんなことをするわけがありません。","ENG":"The Father I know would never do something like this.","TWN":"如果是我認識的神父，絕對不可能做出這種事。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"죽은 이교도들을 위해서, 묘비를 만들어 줄 정도로 상냥한 분이시니까.","JPN":"死んだ異教徒のためにお墓を作って差しあげるほど優しいお方ですから。","ENG":"You're kind enough to make gravestones for dead pagans.","TWN":"因為您是如此溫柔的人，甚至會為死去的異教徒立墓碑。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"틀림없이 무슨 <color=#ffd34c>사정</color>이 있을 거라고 생각했어요.","JPN":"きっと何か<color=#ffd34c>事情</color>があるんだろうと思いました。","ENG":"I was sure there had to be some <color=#ffd34c>reason</color>.","TWN":"我相信您一定有什麼<color=#ffd34c>苦衷</color>。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"그렇게 믿고 있어요.","JPN":"そう信じています。","ENG":"And I still believe that.","TWN":"我是這麼相信的。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"subtitle","speaker":null,"text":{"KOREA":"L20_1","JPN":"L20_1","ENG":"L20_1","TWN":"L20_1","DEU":"L20_1","FRA":"L20_1"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"subtitle","speaker":null,"text":{"KOREA":"L21_1","JPN":"L21_1","ENG":"L21_1","TWN":"L21_1","DEU":"L21_1","FRA":"L21_1"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"L20_1","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"L22_1","slots":{"L":null,"C":{"char_id":"L20_1","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};